#include <stdio.h>

int main() {
    int n, x, y;
    scanf("%d %d %d", &n, &x, &y);
    float num = (y * n) / 100.0;
    int num1 = (y * n) / 100;
    float z = num - num1;
    if (z == 0 && x <= num) {
        printf("%d\n", num1 - x);
    } else if (z != 0 && x <= num) {
        printf("%d\n", num1 + 1 - x);
    } else if (x > num) {
        printf("0\n");
    }
    return 0;
}
